import React from "react";
import { Routes, Route } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Components/Loading/Loading";
import HomePage from "../Pages/HomePage/HomePage";
import Navbar from "./Navbar/navbar";
import Footer from "./Footer/Footer";

function Layout() {
  // Fetch Home data
  const {
    data: homeData,
    isLoading: isLoadingHome,
    isSuccess: isSuccessHome,
    error: homeError,
  } = useQuery({
    queryKey: ["home"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/Home").then((res) => res.json()),
  });

  // Fetch Products data
  const {
    data: productsData,
    isLoading: isLoadingProducts,
    isSuccess: isSuccessProducts,
    error: productsError,
  } = useQuery({
    queryKey: ["products"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/AllProducts").then((res) => res.json()),
  });

  // Combined loading and error states
  const isLoading = isLoadingHome || isLoadingProducts;
  const error = homeError || productsError;

  if (isLoading) {
    return <Loading />;
  }

  if (error) {
    return <p>Error: {error.message}</p>;
  }

  return (
    <Routes>
      <Route
        path="/"
        element={
          <div>
          <Navbar />
          <HomePage
            homeData={homeData}
            isSuccessHome={isSuccessHome}
            productsData={productsData}
            isSuccessProducts={isSuccessProducts}
          />
          <Footer />
        </div>
          
        }
      />
      {/* Add other routes here */}
    </Routes>
  );
}

export default Layout;

